const payload = $json.body ?? $json;
const availableVotes = Number(payload.available_votes ?? 0);
const budgetCents = Number(payload.budget_cents ?? 0);
const recommendations = [];
if (availableVotes > 0) {
  recommendations.push({ title: '优先使用现有票数', reason: '已有票数是最低风险资源，适合先处理临近截止或票差较小的任务。', priority: 'high' });
}
if (budgetCents > 0) {
  recommendations.push({ title: '把预算拆成小批次', reason: '分批投入更容易根据榜单变化调整，不会一次性锁死选择。', priority: 'medium' });
}
if (recommendations.length === 0) {
  recommendations.push({ title: '先同步用户和榜单数据', reason: '当前输入缺少票数或预算信息，建议先补全远程数据库数据再给具体策略。', priority: 'medium' });
}
return [{ json: { skill_id: 'fan.star_consulting.v1', status: 'ok', summary: '已生成一版应援咨询建议。', recommendations, next_actions: [{ type: 'runtime', label: '接入远程数据库后补充用户画像、项目进度和榜单差距。' }], received: payload } }];
